using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;
using ResearchAgent;
using System.ComponentModel;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set AI:ApiKey in configuration or OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(apiKey)));

builder.Services.AddSingleton<NoteService>();
builder.Services.AddSingleton<ResearchTools>();
builder.Services.AddHostedService<ResearchWorker>();

var host = builder.Build();
await host.RunAsync();

namespace ResearchAgent
{
    public sealed class NoteService
    {
        private readonly List<string> _notes = [];

        public void AddNote(string note)
        {
            _notes.Add(note);
            Console.WriteLine($"  [Note saved] {note[..Math.Min(note.Length, 80)]}...");
        }

        public IReadOnlyList<string> GetNotes() => _notes.AsReadOnly();
    }

    public sealed class ResearchTools(NoteService noteService)
    {
        [Description("Search the web for information on a given query. Returns a list of relevant snippets.")]
        public static string SearchWeb(
            [Description("The search query to look up on the web")] string query)
        {
            Console.WriteLine($"  [Searching] \"{query}\"");

            // Simulated web search results for demonstration purposes.
            // Replace with a real search API (Bing, Google, etc.) in production.
            var results = query.ToLowerInvariant() switch
            {
                var q when q.Contains("quantum computing") =>
                    """
                    1. Quantum computers use qubits that can exist in superposition, enabling parallel computation.
                    2. Google's Willow chip (2024) achieved quantum error correction below threshold for the first time.
                    3. IBM plans to deliver 100,000-qubit systems by 2033 through modular architectures.
                    4. Quantum advantage has been demonstrated for specific problems like random circuit sampling.
                    5. Key applications include drug discovery, cryptography, optimization, and materials science.
                    """,
                var q when q.Contains("artificial intelligence") || q.Contains(" ai ") =>
                    """
                    1. Large language models (LLMs) like GPT-4o and Claude power modern AI assistants.
                    2. AI agents can now use tools, browse the web, and execute multi-step plans autonomously.
                    3. The AI industry is projected to reach $1.8 trillion by 2030.
                    4. Key concerns include alignment, hallucination, energy consumption, and job displacement.
                    5. Multimodal AI can process text, images, audio, and video in unified models.
                    """,
                _ =>
                    $"""
                    1. General information about "{query}" is available from multiple sources.
                    2. Recent developments show growing interest in this topic across industries.
                    3. Experts suggest this area will see significant advancement in the next 5 years.
                    4. Key challenges include scalability, cost, and public understanding.
                    5. Multiple research institutions are actively publishing in this domain.
                    """
            };

            return results;
        }

        [Description("Save a research note or key finding for later reference in the summary.")]
        public string TakeNote(
            [Description("The content of the note to save")] string content)
        {
            noteService.AddNote(content);
            return $"Note saved successfully. Total notes: {noteService.GetNotes().Count}";
        }

        [Description("Retrieve all saved research notes.")]
        public string GetAllNotes()
        {
            var notes = noteService.GetNotes();
            if (notes.Count == 0) return "No notes have been saved yet.";
            return string.Join("\n", notes.Select((n, i) => $"{i + 1}. {n}"));
        }
    }

    public sealed class ResearchWorker(
        IChatClient chatClient,
        ResearchTools tools,
        NoteService noteService,
        IHostApplicationLifetime lifetime) : BackgroundService
    {
        protected override async Task ExecuteAsync(CancellationToken stoppingToken)
        {
            Console.WriteLine("═══════════════════════════════════════════");
            Console.WriteLine("  Research Agent — powered by AI");
            Console.WriteLine("═══════════════════════════════════════════");
            Console.Write("\nEnter a topic to research: ");

            var topic = Console.ReadLine()?.Trim();
            if (string.IsNullOrWhiteSpace(topic))
            {
                Console.WriteLine("No topic provided. Exiting.");
                lifetime.StopApplication();
                return;
            }

            Console.WriteLine($"\nResearching: {topic}\n");

            var agent = new ChatClientAgent(chatClient, "ResearchAgent")
            {
                Instructions = """
                    You are a research agent. Your job is to thoroughly research the given topic by:
                    1. Searching the web with multiple relevant queries to gather diverse information.
                    2. Taking notes on the most important findings as you go.
                    3. After gathering enough information, retrieve all your notes and provide a 
                       comprehensive summary with key findings, organized by theme.

                    Be thorough — perform at least 2-3 searches from different angles before summarizing.
                    Always take notes on important findings before moving to the next search.
                    """,
                Tools = [
                    AIFunctionFactory.Create(ResearchTools.SearchWeb),
                    AIFunctionFactory.Create(tools.TakeNote),
                    AIFunctionFactory.Create(tools.GetAllNotes),
                ],
            };

            var options = new AgentInvokeOptions
            {
                MaximumIterations = 10,
            };

            var history = new List<ChatMessage>
            {
                new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}"),
            };

            Console.WriteLine("Agent is working...\n");

            try
            {
                await foreach (var message in agent.InvokeStreamingAsync(history, options, stoppingToken))
                {
                    if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
                    {
                        Console.Write(message.Text);
                    }
                }

                Console.WriteLine("\n\n═══════════════════════════════════════════");
                Console.WriteLine($"  Research complete. {noteService.GetNotes().Count} notes collected.");
                Console.WriteLine("═══════════════════════════════════════════");
            }
            catch (Exception ex)
            {
                Console.WriteLine($"\nError during research: {ex.Message}");
            }

            lifetime.StopApplication();
        }
    }
}

